    it("should include payout and remainingCap in the claim result", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          { op: "quote", items: [{ type: "sword" }] },
          {
            op: "claim",
            policy: 0,
            incident: {
              cause: "fire",
              damages: [{ itemType: "sword", amount: 500 }],
            },
          },
        ],
      });

      expect(result.results[1]).toEqual({ payout: 400, remainingCap: 1600 });
    });
  });

  describe("Errors", () => {
    it("should throw when quoting an item with unknown type (e.g. broomstick)", () => {
      expect(() =>
        processScenario({
          customer: { yearsWithMHPCO: 0 },
          steps: [{ op: "quote", items: [{ type: "broomstick" }] }],
        }),
      ).toThrow();
    });
    it("should throw when a claim damage entry references an item not in the policy", () => {
      expect(() =>
        processScenario({
          customer: { yearsWithMHPCO: 0 },
          steps: [
            { op: "quote", items: [{ type: "sword" }] },
            {
              op: "claim",
              policy: 0,
              incident: {
                cause: "fire",
                damages: [{ itemType: "amulet", amount: 300 }],
              },
            },
          ],
        }),
      ).toThrow();
    });
    it("should throw when there are more damage entries of a type than insured items of that type (two sword damages, one sword insured)", () => {
      expect(() =>
        processScenario({
          customer: { yearsWithMHPCO: 0 },
          steps: [
            { op: "quote", items: [{ type: "sword" }] },
            {
              op: "claim",
              policy: 0,
              incident: {
                cause: "battle",
                damages: [
                  { itemType: "sword", amount: 500 },
                  { itemType: "sword", amount: 300 },
                ],
              },
            },
          ],
        }),
      ).toThrow();
    });
    it.todo("should throw when a damage entry has a negative amount (e.g. -200)");
  });

  describe("Scenario API", () => {
    it.todo("should process a scenario with a quote step followed by a claim step referencing it by zero-based index, returning {premium} and {payout, remainingCap} results");
  });
});

5:describe("MHPCO Claim Office", () => {
6:  describe("Quote: base premiums", () => {
65:  describe("Quote: component building blocks", () => {
161:  describe("Quote: item-specific modifiers", () => {
214:  describe("Quote: policy-wide modifiers", () => {
263:  describe("Quote: rounding and fee", () => {
300:  describe("Quote: integration examples", () => {
334:  describe("Claim: payouts", () => {
502:  describe("Claim: payout cap", () => {
620:  describe("Errors", () => {
668:    it.todo("should throw when a damage entry has a negative amount (e.g. -200)");
671:  describe("Scenario API", () => {
672:    it.todo("should process a scenario with a quote step followed by a claim step referencing it by zero-based index, returning {premium} and {payout, remainingCap} results");

  1	// claim-office.ts
  2	
  3	export type Customer = {
  4	  yearsWithMHPCO: number;
  5	};
  6	
  7	export type Item = {
  8	  type: string;
  9	  material?: string;
 10	  cursed?: boolean;
 11	  enchantment?: number;
 12	};
 13	
 14	export type QuoteStep = {
 15	  op: "quote";
 16	  items: Item[];
 17	};
 18	
 19	export type Damage = {
 20	  itemType: string;
 21	  amount: number;
 22	};
 23	
 24	export type Incident = {
 25	  cause: string;
 26	  damages: Damage[];
 27	};
 28	
 29	export type ClaimStep = {
 30	  op: "claim";
 31	  policy: number;
 32	  incident: Incident;
 33	};
 34	
 35	export type Step = QuoteStep | ClaimStep;
 36	
 37	export type Scenario = {
 38	  customer: Customer;
 39	  steps: Step[];
 40	};
 41	
 42	export type StepResult = {
 43	  premium?: number;
 44	  payout?: number;
 45	  remainingCap?: number;
 46	};
 47	
 48	export type ScenarioResult = {
 49	  results: StepResult[];
 50	};
 51	
 52	const PROCESSING_FEE = 5;
 53	const FIRST_INSURANCE_RATE = 0.1;
 54	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
 55	
 56	type ItemTypeRates = {
 57	  basePremium: number;
 58	  insuranceValue: number;
 59	};
 60	
 61	const COMPONENT_RATES: ItemTypeRates = { basePremium: 25, insuranceValue: 250 };
 62	
 63	const ITEM_TYPE_RATES: Record<string, ItemTypeRates> = {
 64	  sword: { basePremium: 100, insuranceValue: 1000 },
 65	  amulet: { basePremium: 60, insuranceValue: 600 },
 66	  staff: { basePremium: 80, insuranceValue: 800 },
 67	  potion: { basePremium: 40, insuranceValue: 400 },
 68	  rune: COMPONENT_RATES,
 69	  moonstone: COMPONENT_RATES,
 70	};
 71	
 72	const COMPONENT_BLOCK_SIZE = 3;
 73	const COMPONENT_BLOCK_PRICE = 60;
 74	
 75	const LOYALTY_DISCOUNT_RATE = 0.2;
 76	const LOYALTY_YEARS_THRESHOLD = 2;
 77	
 78	const CURSE_SURCHARGE_RATE = 0.5;
 79	const ENCHANTMENT_SURCHARGE_RATE = 0.3;
 80	const HIGH_ENCHANTMENT_THRESHOLD = 5;
 81	
 82	const ratesOf = (type: string): ItemTypeRates => {
 83	  const rates = ITEM_TYPE_RATES[type];
 84	  if (rates === undefined) {
 85	    throw new Error(`unknown item type: ${type}`);
 86	  }
 87	  return rates;
 88	};
 89	
 90	const basePremiumOf = (type: string): number => ratesOf(type).basePremium;
 91	
 92	const roundUpInMHPCOFavor = (amount: number): number => Math.ceil(amount);
 93	
 94	const roundDownInMHPCOFavor = (amount: number): number => Math.floor(amount);
 95	
 96	const typeGroupPremiumOf = (type: string, count: number): number =>
 97	  count === COMPONENT_BLOCK_SIZE
 98	    ? COMPONENT_BLOCK_PRICE
 99	    : count * basePremiumOf(type);
100	
101	const surchargeOf = (
102	  items: Item[],
103	  appliesTo: (item: Item) => boolean,
104	  rate: number,
105	): number =>
106	  items.reduce(
107	    (surcharge, item) =>
108	      appliesTo(item)
109	        ? surcharge + basePremiumOf(item.type) * rate
110	        : surcharge,
111	    0,
112	  );
113	
114	const curseSurchargeOf = (items: Item[]): number =>
115	  surchargeOf(items, (item) => Boolean(item.cursed), CURSE_SURCHARGE_RATE);
116	
117	const enchantmentOf = (item: Item): number => item.enchantment ?? 0;
118	
119	const enchantmentSurchargeOf = (items: Item[]): number =>
120	  surchargeOf(
121	    items,
122	    (item) => enchantmentOf(item) >= HIGH_ENCHANTMENT_THRESHOLD,
123	    ENCHANTMENT_SURCHARGE_RATE,
124	  );
125	
126	const policyBasePremiumOf = (items: Item[]): number => {
127	  const countsByType = new Map<string, number>();
128	  for (const item of items) {
129	    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
130	  }
131	  return [...countsByType].reduce(
132	    (typeGroupsPremium, [type, count]) =>
133	      typeGroupsPremium + typeGroupPremiumOf(type, count),
134	    0,
135	  );
136	};
137	
138	const loyaltyDiscountOf = (
139	  customer: Customer,
140	  policyBasePremium: number,
141	): number =>
142	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
143	    ? policyBasePremium * LOYALTY_DISCOUNT_RATE
144	    : 0;
145	
146	const followUpDiscountOf = (
147	  isFollowUpQuote: boolean,
148	  policyBasePremium: number,
149	): number => (isFollowUpQuote ? policyBasePremium * FOLLOW_UP_DISCOUNT_RATE : 0);
150	
151	const quotePremiumOf = (
152	  customer: Customer,
153	  items: Item[],
154	  isFollowUpQuote: boolean,
155	): number => {
156	  const policyBasePremium = policyBasePremiumOf(items);
157	  const itemSurcharges = curseSurchargeOf(items) + enchantmentSurchargeOf(items);
158	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_RATE;
159	  const loyaltyDiscount = loyaltyDiscountOf(customer, policyBasePremium);
160	  const followUpDiscount = followUpDiscountOf(isFollowUpQuote, policyBasePremium);
161	  return roundUpInMHPCOFavor(
162	    policyBasePremium +
163	      itemSurcharges +
164	      firstInsuranceSurcharge -
165	      loyaltyDiscount -
166	      followUpDiscount +
167	      PROCESSING_FEE,
168	  );
169	};
170	
171	const PAYOUT_CAP_FACTOR = 2;
172	
173	const DEDUCTIBLE = 100;
174	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
175	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
176	
177	const processQuote = (
178	  customer: Customer,
179	  quote: QuoteStep,
180	  isFollowUpQuote: boolean,
181	): StepResult => ({
182	  premium: quotePremiumOf(customer, quote.items, isFollowUpQuote),
183	});
184	
185	const takeInsuredItemFor = (availableItems: Item[], damage: Damage): Item => {
186	  const index = availableItems.findIndex(
187	    (item) => item.type === damage.itemType,
188	  );
189	  if (index === -1)
190	    throw new Error(`item not covered by policy: ${damage.itemType}`);
191	  const [insuredItem] = availableItems.splice(index, 1);
192	  return insuredItem;
193	};
194	
195	const reimbursementOf = (damage: Damage, insuredItem: Item): number =>
196	  enchantmentOf(insuredItem) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
197	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
198	    : damage.amount;
199	
200	const insuranceSumOf = (items: Item[]): number =>
201	  items.reduce((sum, item) => sum + ratesOf(item.type).insuranceValue, 0);
202	
203	const payoutCapOf = (policy: QuoteStep): number =>
204	  insuranceSumOf(policy.items) * PAYOUT_CAP_FACTOR;
205	
206	const processClaim = (
207	  claim: ClaimStep,
208	  steps: Step[],
209	  remainingCaps: Map<number, number>,
210	): StepResult => {
211	  const policy = steps[claim.policy] as QuoteStep;
212	  const availableCap = remainingCaps.get(claim.policy) ?? payoutCapOf(policy);
213	  const availableItems = [...policy.items];
214	  const uncappedPayout = claim.incident.damages.reduce(
215	    (total, damage) =>
216	      total +
217	      reimbursementOf(damage, takeInsuredItemFor(availableItems, damage)) -
218	      DEDUCTIBLE,
219	    0,
220	  );
221	  const payout = Math.min(roundDownInMHPCOFavor(uncappedPayout), availableCap);
222	  const remainingCap = availableCap - payout;
223	  remainingCaps.set(claim.policy, remainingCap);
224	  return { payout, remainingCap };
225	};
226	
227	export const processScenario = (scenario: Scenario): ScenarioResult => {
228	  const remainingCaps = new Map<number, number>();
229	  return {
230	    results: scenario.steps.map((step, stepIndex) =>
231	      step.op === "quote"
232	        ? processQuote(scenario.customer, step, stepIndex > 0)
233	        : processClaim(step, scenario.steps, remainingCaps),
234	    ),
235	  };
236	};

